args.sparql:
SELECT DISTINCT ?series ?seriesLabel WHERE {
  ?series wdt:P31 wd:Q4167836 .
  ?series rdfs:label ?seriesLabel .
  FILTER (CONTAINS(LCASE(?seriesLabel), 'percy jackson and the olympians') && LANG(?seriesLabel) = 'en')
}

SELECT DISTINCT ?movie ?movieLabel ?releaseDate WHERE {
  ?movie wdt:P31 wd:Q11424 .
  ?movie rdfs:label ?movieLabel .
  FILTER (CONTAINS(LCASE(?movieLabel), "percy jackson") && LANG(?movieLabel) = "en")
  ?movie wdt:P577 ?releaseDate
} ORDER BY ?releaseDate
